/// Extracts the first grapheme cluster of the string and returns it as a
/// string, or extracts the first `count` grapheme clusters and returns
/// them as an array if `count` is given.
/// Fails with an error if the string is empty, or if `count` exceeds the
/// number of grapheme clusters in the string.
#[func]
pub fn first(
    &self,
    /// Number of grapheme clusters to return as an array. If omitted, a
    /// single string is returned.
    #[named]
    count: Option<usize>,
    /// Characters to strip from the start of the string before
    /// extracting the first grapheme cluster(s).
    #[named]
    strip: Option<Str>,
) -> StrResult<Value> {
    let s = match &strip {
        Some(strip) => {
            self.0.trim_start_matches(|c: char| strip.as_str().contains(c))
        }
        None => self.0.as_str(),
    };

    match count {
        None => s
            .graphemes(true)
            .next()
            .map(IntoValue::into_value)
            .ok_or_else(string_is_empty),
        Some(count) => {
            let graphemes: Vec<&str> = s.graphemes(true).collect();
            if count > graphemes.len() {
                bail!(count_exceeds_length(count, graphemes.len()));
            }
            Ok(graphemes[..count]
                .iter()
                .map(|s| s.into_value())
                .collect::<Array>()
                .into_value())
        }
    }
}

/// Extracts the last grapheme cluster of the string and returns it as a
/// string, or extracts the last `count` grapheme clusters and returns
/// them as an array if `count` is given.
/// Fails with an error if the string is empty, or if `count` exceeds the
/// number of grapheme clusters in the string.
#[func]
pub fn last(
    &self,
    /// Number of grapheme clusters to return as an array. If omitted, a
    /// single string is returned.
    #[named]
    count: Option<usize>,
    /// Characters to strip from the end of the string before extracting
    /// the last grapheme cluster(s).
    #[named]
    strip: Option<Str>,
) -> StrResult<Value> {
    let s = match &strip {
        Some(strip) => {
            self.0.trim_end_matches(|c: char| strip.as_str().contains(c))
        }
        None => self.0.as_str(),
    };

    match count {
        None => s
            .graphemes(true)
            .next_back()
            .map(IntoValue::into_value)
            .ok_or_else(string_is_empty),
        Some(count) => {
            let graphemes: Vec<&str> = s.graphemes(true).collect();
            if count > graphemes.len() {
                bail!(count_exceeds_length(count, graphemes.len()));
            }
            let start = graphemes.len() - count;
            Ok(graphemes[start..]
                .iter()
                .map(|s| s.into_value())
                .collect::<Array>()
                .into_value())
        }
    }
}

